/**
 * TaskCreate
 */
export type TaskCreate = {
    /**
     * Name
     *
     * 任务显示名称；不传时由系统根据 Agent、Target 和任务类型生成。
     */
    name?: string | null;
    /**
     * Description
     *
     * 任务描述。
     */
    description?: string | null;
    /**
     * Target Uuid
     *
     * 任务关联的 Target UUID。
     */
    target_uuid: string;
    /**
     * Agent Uuid
     *
     * 任务关联的 Agent UUID。
     */
    agent_uuid: string;
    /**
     * Task Type
     *
     * 任务类型，可选 `icmp`、`tcp`、`mtr` 或 `iperf3`。
     */
    task_type: 'icmp' | 'tcp' | 'mtr' | 'iperf3';
    /**
     * Ip Family
     *
     * 任务使用的 IP 协议族，可选 `4` 或 `6`。
     */
    ip_family: '4' | '6';
    /**
     * Interval
     *
     * 任务执行间隔，单位为秒。
     */
    interval?: number;
    /**
     * Timeout
     *
     * 单次探测超时时间，单位为毫秒。
     */
    timeout?: number;
    /**
     * Packet Count
     *
     * 单次探测发送的包数量或连接尝试数量。
     */
    packet_count?: number;
    /**
     * Probe Config
     *
     * 任务类型相关的探测配置，例如 TCP 端口、MTR 最大跳数等。
     */
    probe_config?: {
        [key: string]: unknown;
    };
    /**
     * Mtr Retry Config
     *
     * MTR 重试配置，仅对 MTR 任务生效。
     */
    mtr_retry_config?: {
        [key: string]: unknown;
    } | null;
    /**
     * Schedule Jitter Ms
     *
     * 调度抖动上限，单位为毫秒，用于避免大量任务同时触发。
     */
    schedule_jitter_ms?: number;
    /**
     * Created By Relation
     *
     * 是否由快速关联流程自动创建。
     */
    created_by_relation?: boolean;
};

